export async function POST(req) {
  const auth = requireAdmin(req); if (auth) return auth;
  
  let updated = 0;
  for (const w of WILAYAS_AR) {
    await prisma.wilaya.updateMany({ where: { id: w.id }, data: { name_ar: w.name_ar } });
    updated++;
  }
  
  for (const c of COMMUNES_AR) {
    await prisma.commune.updateMany({
      where: { name: c.name, wilayaId: c.wilayaId },
      data: { name_ar: c.name_ar },
    });
  }
  
  return Response.json({ ok: true, wilayas: updated, communes: COMMUNES_AR.length });
}
